# Refactoring Auth: Session Cookies → OAuth 2.0

## Migration Overview

This is a large-surface refactor. Below is a comprehensive, step-by-step transformation from a typical session-cookie auth system to OAuth 2.0 (Authorization Code flow with PKCE).

---

## Before (Session Cookie Auth)

```python
# ──────────────────────────────────────────────────
# auth/session.py — OLD: Session-cookie based auth
# ──────────────────────────────────────────────────
import hashlib, os, time
from functools import wraps
from flask import Flask, request, redirect, session, jsonify, make_response
from werkzeug.security import generate_password_hash, check_password_hash
from database import db, User  # ORM model

app = Flask(__name__)
app.secret_key = os.environ["FLASK_SECRET"]  # used to sign session cookies

# ─── Registration / Login (local password store) ───

@app.route("/register", methods=["POST"])
def register():
    data = request.json
    if User.query.filter_by(email=data["email"]).first():
        return jsonify(error="Email already registered"), 409

    user = User(
        email=data["email"],
        password_hash=generate_password_hash(data["password"]),
    )
    db.session.add(user)
    db.session.commit()
    return jsonify(id=user.id), 201


@app.route("/login", methods=["POST"])
def login():
    data = request.json
    user = User.query.filter_by(email=data["email"]).first()

    if not user or not check_password_hash(user.password_hash, data["password"]):
        return jsonify(error="Invalid credentials"), 401

    # Store user ID in the server-side (or signed client-side) session cookie
    session["user_id"] = user.id
    session["login_time"] = time.time()
    return jsonify(message="Logged in")


@app.route("/logout", methods=["POST"])
def logout():
    session.clear()
    return jsonify(message="Logged out")


# ─── Auth decorator (relied on session cookie) ───

def login_required(f):
    @wraps(f)
    def decorated(*args, **kwargs):
        user_id = session.get("user_id")
        if not user_id:
            return jsonify(error="Authentication required"), 401

        user = db.session.get(User, user_id)
        if not user:
            session.clear()
            return jsonify(error="User not found"), 401

        # Attach user object to request context
        request.current_user = user
        return f(*args, **kwargs)
    return decorated


# ─── Protected endpoint example ───

@app.route("/api/profile", methods=["GET"])
@login_required
def get_profile():
    user = request.current_user
    return jsonify(email=user.email, created_at=user.created_at.isoformat())


